import{_ as t,a,b as r,c as d,d as o,e as l,f as n}from"./chunks/添加dc新渠道配置.jxAOeu6M.js";import{_ as i,o as s,c,a2 as h}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Discord Channel சேர்க்கவும்","description":"","frontmatter":{},"headers":[],"relativePath":"ta/upload/discord.md","filePath":"ta/upload/discord.md","lastUpdated":1781962217000}'),p={name:"ta/upload/discord.md"};function b(g,e,u,m,v,D){return s(),c("div",null,[...e[0]||(e[0]=[h('<h1 id="discord-channel-சேர்க்கவும்" tabindex="-1">Discord Channel சேர்க்கவும் <a class="header-anchor" href="#discord-channel-சேர்க்கவும்" aria-label="Permalink to &quot;Discord Channel சேர்க்கவும்&quot;">​</a></h1><h2 id="தொடங்குவதற்கு-முன்-தேவையானவை" tabindex="-1">தொடங்குவதற்கு முன் தேவையானவை <a class="header-anchor" href="#தொடங்குவதற்கு-முன்-தேவையானவை" aria-label="Permalink to &quot;தொடங்குவதற்கு முன் தேவையானவை&quot;">​</a></h2><table tabindex="0"><thead><tr><th>தேவை</th><th>பயன்பாடு</th></tr></thead><tbody><tr><td>Discord account</td><td>server, channel, developer application உருவாக்க</td></tr><tr><td>Discord server</td><td>bot channel அணுகுவதற்கு முன் server-ல் join ஆக வேண்டும்</td></tr><tr><td>Text channel</td><td>images மற்றும் files இந்த channel-க்கு அனுப்பப்படும்</td></tr><tr><td>Discord Developer Portal</td><td>application, bot உருவாக்கி <code>Bot Token</code> பெற</td></tr></tbody></table><h2 id="எங்கு-சேர்ப்பது" tabindex="-1">எங்கு சேர்ப்பது <a class="header-anchor" href="#எங்கு-சேர்ப்பது" aria-label="Permalink to &quot;எங்கு சேர்ப்பது&quot;">​</a></h2><ol><li>System Settings திறக்கவும்.</li><li>Upload Settings-க்கு செல்லவும்.</li><li>மேல் வலது மூலையில் Add Channel கிளிக் செய்யவும்.</li><li><code>Discord</code> தேர்வு செய்யவும்.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>பயன்பாடு</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>இந்த channel-க்கு பெயர், உதா. <code>Discord Primary</code>.</td><td>Required</td></tr><tr><td>Bot Token</td><td>Discord bot token.</td><td>Required</td></tr><tr><td>Channel ID</td><td>target text channel ID.</td><td>Required</td></tr><tr><td>Proxy URL (optional)</td><td>Discord CDN access unstable என்றால் மட்டும். <code>https://</code> உடன் full URL.</td><td>Optional</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="_1-discord-server-மற்றும்-text-channel-உருவாக்கவும்" tabindex="-1">1. Discord Server மற்றும் Text Channel உருவாக்கவும் <a class="header-anchor" href="#_1-discord-server-மற்றும்-text-channel-உருவாக்கவும்" aria-label="Permalink to &quot;1. Discord Server மற்றும் Text Channel உருவாக்கவும்&quot;">​</a></h3><ol><li>Discord திறக்கவும்.</li><li>புதிய server உருவாக்கவும், அல்லது உங்களுடைய existing server பயன்படுத்தவும்.</li><li>அந்த server-ல் text channel உருவாக்கவும்.</li></ol><p><img src="'+t+'" alt="Create a server" loading="lazy"></p><h3 id="_2-discord-developer-portal-ல்-bot-உருவாக்கவும்" tabindex="-1">2. Discord Developer Portal-ல் Bot உருவாக்கவும் <a class="header-anchor" href="#_2-discord-developer-portal-ல்-bot-உருவாக்கவும்" aria-label="Permalink to &quot;2. Discord Developer Portal-ல் Bot உருவாக்கவும்&quot;">​</a></h3><ol><li>Discord Developer Portal திறக்கவும்: <code>https://discord.com/developers/applications</code></li><li><code>New Application</code> கிளிக் செய்யவும்.</li><li>application name உள்ளிட்டு create செய்யவும்.</li><li>left sidebar-ல் <code>Bot</code> page திறக்கவும்.</li><li><code>Bot</code> page-ல் token generate அல்லது reset செய்யவும்.</li><li>token சேமிக்கவும்.</li></ol><p>இந்த token தான் ImgBed-ல் <code>Bot Token</code>.</p><p><img src="'+a+'" alt="View the bot token" loading="lazy"></p><h3 id="_3-oauth2-invite-link-உருவாக்கி-bot-install-செய்யவும்" tabindex="-1">3. OAuth2 Invite Link உருவாக்கி Bot Install செய்யவும் <a class="header-anchor" href="#_3-oauth2-invite-link-உருவாக்கி-bot-install-செய்யவும்" aria-label="Permalink to &quot;3. OAuth2 Invite Link உருவாக்கி Bot Install செய்யவும்&quot;">​</a></h3><ol><li>left sidebar-ல் <code>OAuth2</code> page திறக்கவும்.</li><li>scopes பகுதியில் <code>bot</code> தேர்வு செய்யவும்.</li><li>permission area-ல் இவற்றை enable செய்யவும்:</li></ol><table tabindex="0"><thead><tr><th>Permission</th><th>Required</th></tr></thead><tbody><tr><td>View Channels</td><td>Yes</td></tr><tr><td>Send Messages</td><td>Yes</td></tr><tr><td>Attach Files</td><td>Yes</td></tr><tr><td>Read Message History</td><td>Yes</td></tr></tbody></table><ol start="4"><li>page கீழே integration type <code>Guild Install</code> என்பதைக் confirm செய்யவும்.</li><li>generated URL copy செய்யவும்.</li><li>browser-ல் அந்த URL திறக்கவும்.</li><li>target server தேர்வு செய்யவும்.</li><li>authorization flow முடிக்கவும்.</li></ol><p><img src="'+r+'" alt="Select bot permissions in OAuth2" loading="lazy"></p><p><img src="'+d+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-developer-mode-enable-செய்து-channel-id-copy-செய்யவும்" tabindex="-1">4. Developer Mode Enable செய்து Channel ID Copy செய்யவும் <a class="header-anchor" href="#_4-developer-mode-enable-செய்து-channel-id-copy-செய்யவும்" aria-label="Permalink to &quot;4. Developer Mode Enable செய்து Channel ID Copy செய்யவும்&quot;">​</a></h3><ol><li>Discord கீழ் இடது பகுதியில் avatar அருகிலுள்ள gear icon கிளிக் செய்யவும்.</li><li>left sidebar-ல் Advanced திறக்கவும்.</li><li>Developer Mode enable செய்யவும்.</li><li>target text channel-க்கு திரும்பவும்.</li><li>channel name மீது right-click செய்யவும்.</li><li>Copy Channel ID கிளிக் செய்யவும்.</li></ol><p>copy செய்யப்பட்ட number தான் ImgBed-க்கு தேவையான <code>Channel ID</code>.</p><p><img src="'+o+'" alt="Enable developer mode" loading="lazy"></p><p><img src="'+l+'" alt="Copy the channel ID" loading="lazy"></p><h3 id="_5-imgbed-ல்-discord-channel-நிரப்பவும்" tabindex="-1">5. ImgBed-ல் Discord Channel நிரப்பவும் <a class="header-anchor" href="#_5-imgbed-ல்-discord-channel-நிரப்பவும்" aria-label="Permalink to &quot;5. ImgBed-ல் Discord Channel நிரப்பவும்&quot;">​</a></h3><p>configuration dialog-க்கு திரும்பி:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel name</td><td>custom channel name, உதா. <code>DiscordPrimary</code>.</td></tr><tr><td>Bot Token</td><td>Discord Developer Portal <code>Bot</code> page-ல் சேமித்த token.</td></tr><tr><td>Channel ID</td><td>Discord-ல் copy செய்த channel ID.</td></tr><tr><td>Proxy URL (optional)</td><td>தேவைப்பட்டால் மட்டும், உதா. <code>https://your-proxy.example.com</code>.</td></tr></tbody></table><p>முடிந்ததும் Save கிளிக் செய்யவும்.</p><p><img src="'+n+`" alt="Add the Discord channel configuration" loading="lazy"></p><h2 id="verify-செய்வது" tabindex="-1">Verify செய்வது <a class="header-anchor" href="#verify-செய்வது" aria-label="Permalink to &quot;Verify செய்வது&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>சரிபார்ப்பு</th></tr></thead><tbody><tr><td>Channel card appears</td><td>Save செய்த பிறகு Discord channel card தெரியும்.</td></tr><tr><td>Channel can be enabled</td><td>Active switch on ஆக இருக்கும்.</td></tr><tr><td>Configuration is saved</td><td>detail view-ல் Bot Token மற்றும் Channel ID saved என தெரியும்.</td></tr><tr><td>Upload works</td><td>test image upload செய்து target Discord text channel-ல் வந்ததா பார்க்கவும்.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Discord server உருவாக்கவும்</span></span>
<span class="line"><span>-&gt; text channel உருவாக்கவும்</span></span>
<span class="line"><span>-&gt; Discord Developer Portal-ல் bot உருவாக்கவும்</span></span>
<span class="line"><span>-&gt; Bot page-ல் Bot Token சேமிக்கவும்</span></span>
<span class="line"><span>-&gt; OAuth2-ல் bot, View Channels, Send Messages, Attach Files, Read Message History தேர்வு செய்யவும்</span></span>
<span class="line"><span>-&gt; generated URL copy செய்து target server-க்கு bot authorize செய்யவும்</span></span>
<span class="line"><span>-&gt; target text channel permissions சரியா பார்க்கவும்</span></span>
<span class="line"><span>-&gt; Developer Mode enable செய்யவும்</span></span>
<span class="line"><span>-&gt; target text channel-ல் right-click செய்து Channel ID copy செய்யவும்</span></span>
<span class="line"><span>-&gt; ImgBed-ல் Bot Token மற்றும் Channel ID நிரப்பவும்</span></span>
<span class="line"><span>-&gt; Save செய்து test image upload செய்யவும்</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Discord Developers Getting Started: <a href="https://docs.discord.com/developers/quick-start/getting-started" target="_blank" rel="noreferrer">https://docs.discord.com/developers/quick-start/getting-started</a></li><li>Discord Help - Where can I find my User/Server/Message ID: <a href="https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID" target="_blank" rel="noreferrer">https://support.discord.com/hc/en-us/articles/206346498-Where-can-I-find-my-User-Server-Message-ID</a></li></ol>`,37)])])}const y=i(p,[["render",b]]);export{_ as __pageData,y as default};
